const item = $input.first().json;

function formatWhatsAppBR(input) {
  const digits = String(input || '').replace(/\D/g, '');

  let clean = digits;

  if (clean.startsWith('55')) {
    clean = clean.slice(2);
  }

  if (!/^\d{10,11}$/.test(clean)) {
    throw new Error('WhatsApp inválido Use DDD número Ex 7193673276 ou 71987654321');
  }

  const ddd = clean.slice(0, 2);
  const numero = clean.slice(2);

  const formatado = numero.length === 9
    ? `+55 (${ddd}) ${numero.slice(0, 5)}-${numero.slice(5)}`
    : `+55 (${ddd}) ${numero.slice(0, 4)}-${numero.slice(4)}`;

  return {
    formatado,
    e164: `55${clean}`
  };
}

function validarData(data) {
  const valor = String(data || '').trim();

  if (!/^\d{4}-\d{2}-\d{2}$/.test(valor)) {
    throw new Error('Data inválida Use uma data válida no formulário');
  }

  return valor;
}

function validarHoraParte(valor, nome, min, max) {
  const texto = String(valor ?? '').trim();

  if (!/^\d{1,2}$/.test(texto)) {
    throw new Error(`${nome} inválido Use apenas números`);
  }

  const numero = Number(texto);

  if (Number.isNaN(numero) || numero < min || numero > max) {
    throw new Error(`${nome} inválido. Deve estar entre ${min} e ${max}.`);
  }

  return String(numero).padStart(2, '0');
}

function extrairIdsCrm(link) {
  const valor = String(link || '').trim();

  const matchConversation = valor.match(/\/conversations\/(\d+)/);
  const matchContact = valor.match(/\/contacts\/(\d+)/);

  return {
    conversation_id: matchConversation ? matchConversation[1] : '',
    contact_id: matchContact ? matchContact[1] : ''
  };
}

const dataEnvio = validarData(item.data_envio);
const hora = validarHoraParte(item.hora_envio, 'Hora', 0, 23);
const minuto = validarHoraParte(item.minuto_envio, 'Minuto', 0, 59);
const whatsapp = formatWhatsAppBR(item.whatsapp);
const idsCrm = extrairIdsCrm(item.link_crm);

const horaEnvio = `${hora}:${minuto}`;
const dataHoraLocal = `${dataEnvio} ${horaEnvio}:00`;
const dataHoraISO = `${dataEnvio}T${horaEnvio}:00-03:00`;

return [
  {
    json: {
      ...item,
      link_crm: item.link_crm.split("?")[0],
      hora_envio_normalizada: horaEnvio,
      whatsapp_formatado: whatsapp.formatado,
      whatsapp_e164: whatsapp.e164,
      data_hora_envio: dataHoraLocal,
      data_hora_envio_iso: dataHoraISO,
      conversation_id: idsCrm.conversation_id,
      contact_id: idsCrm.contact_id
    }
  }
];

